<section class="card form-card"><h2>Log transaction</h2><form class="grid-form" method="post" action="/transactions/create"><?= csrf_field() ?><label>Plot <select name="plot_id" data-autocomplete><?php foreach ($plots as $plot): ?><option value="<?= e($plot['id']) ?>"><?= e($plot['plot_number']) ?></option><?php endforeach; ?></select></label><label>From owner UUID <input name="from_owner_id"></label><label>To owner <select name="to_owner_id"><?php foreach ($owners as $owner): ?><option value="<?= e($owner['id']) ?>"><?= e($owner['full_name']) ?></option><?php endforeach; ?></select></label><label>Type <select name="transaction_type"><option>sale</option><option>lease</option><option>inheritance</option><option>gift</option><option>government_allocation</option><option>revocation</option></select></label><label>Amount <input type="number" step="0.01" name="amount"></label><label>Currency <input name="currency" value="NGN"></label><label>Date <input type="date" name="transaction_date" required></label><label class="span-2">Notes <textarea name="notes"></textarea></label><button class="btn primary">Save transaction</button></form></section>
